const projectsRaw = $('HTTP — Fetch Week Projects').first().json;
const docsRaw = $('HTTP — Fetch Week Documents').first().json;
const projects = Array.isArray(projectsRaw) ? projectsRaw : [];
const docs = Array.isArray(docsRaw) ? docsRaw : [];

// Category breakdown
const categoryCount = {};
projects.forEach(p => { categoryCount[p.category || 'other'] = (categoryCount[p.category || 'other'] || 0) + 1; });

// Complexity stats
const avgComplexity = projects.length ? (projects.reduce((s, p) => s + (p.complexity_score || 0), 0) / projects.length).toFixed(1) : 0;

// Priority breakdown
const criticalCount = projects.filter(p => p.priority === 'critical').length;
const highCount = projects.filter(p => p.priority === 'high').length;

const weekStart = new Date();
weekStart.setDate(weekStart.getDate() - 7);

const context = {
  week_start: weekStart.toISOString().split('T')[0],
  generated_at: new Date().toISOString(),
  project_count: projects.length,
  doc_count: docs.length,
  category_breakdown: categoryCount,
  avg_complexity: avgComplexity,
  critical_projects: criticalCount,
  high_priority_projects: highCount,
  projects_summary: projects.map(p => ({ title: p.project_title, client: p.client_name, category: p.category, complexity: p.complexity_score, priority: p.priority, summary: p.ai_summary })),
  doc_topics: docs.flatMap(d => d.main_topics || []).filter((v, i, a) => a.indexOf(v) === i).slice(0, 10)
};

return [{ json: context }];

