parameters.jsCode:
const aiResponse = $input.first().json;
const markdown = aiResponse.candidates?.[0]?.content?.parts?.[0]?.text || 'Report generation failed.';
const context = $('Code — Aggregate Report Data').first().json;

// Simple markdown-to-HTML conversion
let html = markdown
  .replace(/^# (.+)$/mg, '<h1>$1</h1>')
  .replace(/^## (.+)$/mg, '<h2>$1</h2>')
  .replace(/^### (.+)$/mg, '<h3>$1</h3>')
  .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  .replace(/\*(.+?)\*/g, '<em>$1</em>')
  .replace(/^- (.+)$/mg, '<li>$1</li>')
  .replace(/^\d+\. (.+)$/mg, '<li>$1</li>')
  .replace(/<\/li>\n<li>/g, '</li><li>')
  .replace(/(<li>.*<\/li>)/gs, '<ul>$1</ul>')
  .replace(/\n/g, '<br/>');

const reportHtml = `<!DOCTYPE html><html><head><meta charset="UTF-8"><style>body{font-family:Inter,sans-serif;max-width:900px;margin:2rem auto;padding:2rem;color:#1a1a2e;background:#f8f9fa}h1{color:#6c63ff;border-bottom:3px solid #6c63ff;padding-bottom:0.5rem}h2{color:#2d2d4e;margin-top:2rem}h3{color:#6c63ff}table{border-collapse:collapse;width:100%;margin:1rem 0}th{background:#6c63ff;color:white;padding:10px;text-align:left}td{border:1px solid #ddd;padding:8px}tr:nth-child(even){background:#f2f0ff}ul{padding-left:1.5rem}li{margin:0.3rem 0}strong{color:#2d2d4e}.meta{font-size:0.8rem;color:#888;margin-bottom:2rem}</style></head><body><div class="meta">Generated: ${new Date().toLocaleString()} | Projects: ${context.project_count} | Documents: ${context.doc_count}</div>${html}</body></html>`;

return [{ json: { report_markdown: markdown, report_html: reportHtml, week_start: context.week_start, project_count: context.project_count, doc_count: context.doc_count } }];

